const items = $input.all();

if (items.length === 0) {
  return [{ json: { message: ':bar_chart: **Rapport Hebdo — Pellet Distribution**\n\nAucune commande cette semaine.' } }];
}

let totalCA = 0;
const parStatut = {};
const lignes = [];

for (const item of items) {
  const f = item.json.fields ?? item.json;
  const montant = parseFloat(f['Montant'] ?? 0);
  const statut = f['Statut'] ?? 'Inconnu';
  const client = f['Client'] ?? '?';
  totalCA += montant;
  parStatut[statut] = (parStatut[statut] ?? 0) + 1;
  lignes.push(`• ${client} — ${statut}${montant ? ` — ${montant} €` : ''}`);
}

const statsStatut = Object.entries(parStatut)
  .map(([s, n]) => `  ${s}: ${n}`)
  .join('\n');

const now = new Date();
const dateStr = now.toLocaleDateString('fr-FR', { weekday: 'long', day: 'numeric', month: 'long' });

const message = `:bar_chart: **Rapport Hebdo — Pellet Distribution**\n*Semaine du ${dateStr}*\n\n**Total commandes :** ${items.length}\n**CA total :** ${totalCA.toFixed(2)} €\n\n**Par statut :**\n${statsStatut}\n\n**Détail :**\n${lignes.slice(0, 15).join('\n')}${items.length > 15 ? `\n… et ${items.length - 15} autres` : ''}`;

return [{ json: { message, count: items.length, ca: totalCA } }];
